    Climate = factor(
      case_when(
        ptot &lt; (athr/2) ~ "Arid (TP &lt; AT/2)",
        ptot &lt;= athr    ~ "Semi-Arid (TP &lt;= AT",
        TRUE            ~ "Not Dry (Pt &gt;= AT)"),
      levels = c(
        "Arid (TP &lt; AT/2)", 
