4.8 Functions

4.8.1 Assign KTC Group


Code
fn_assign_grp &lt;- function(df) {
  df &lt;- df |&gt;
    mutate(
      grp = case_when(
        tmax &lt; 10 ~ "F",
        ptot &lt; athr ~ "B",
        tmin &gt;= 18 ~ "A",
        tg10 &gt;= 8 ~ "C",
        tg10 &gt;= 4 ~ "D",
        tg10 &gt;= 1 ~ "E",
        TRUE ~ "X"
      )
    )
  return(df)
}




4.8.2 Assign KTC Type


Code
fn_assign_typ &lt;- function(df) {
  df &lt;- df |&gt;
    mutate(
      cls = case_when(
        grp == "A" & (pl60 &lt;= 2) ~ "r",
        grp == "A" ~ "w",
        grp == "B" & (ptot &lt; athr/2) ~ "W",
        grp == "B" ~ "S",

        grp == "C" & (wtot &gt;= stot * 3) & (pmin &lt; 30) & (ptot &lt; 890) ~ "s",
        grp == "C" & (stot &gt;= wtot * 10) ~ "w",
        grp == "C" ~ "f",

        grp == "D" & (tmin &gt; 0) ~ "o",
        grp == "D" ~ "c",
        grp == "F" & (tmax &gt; 0) ~ "t",
        grp == "F" ~ "i",
        TRUE ~ ""
      ),
      typ = paste(grp, cls, sep = "")
    )
  df &lt;- df|&gt; select(lon, lat, area, lsm, grp, typ)
  return(df)
}




