fn_build_detail_table &lt;- function(df, subtitle) {

  tbl &lt;- df |&gt;
    gt(rowname_col = "cgrp" ) |&gt;
    tab_stubhead(label = "From Group")|&gt;
    tab_header(
      title = "Climate Classification Changes Detail",
      subtitle = subtitle
    ) |&gt;
    cols_label(
      rgrp = "To Group",
      mkm = "Area (Mkm²)",
      pct = "Land Area %",
    ) |&gt;
    fmt_number(
      columns = mkm,
      decimals = 1
    ) |&gt;
    fmt_percent(
      columns = pct,
      decimals = 2 
    ) |&gt;
    # cols_width(
    #     col_a ~ px(150), # Set col_a to 150 pixels
    #     col_b ~ pct(10), # Set col_b to 10% of table width
    #     everything() ~ px(200) # Set all other columns to 200 pixels
    # ) |&gt;
    grand_summary_rows(
      columns = mkm,
      fns = list("Total" = ~ sum(.)),
      fmt = list(~ fmt_number(.x, decimals = 1))
    ) |&gt;
    grand_summary_rows(
      columns = pct,
      fns = list("Total" = ~ sum(.)),
      fmt = list(~ fmt_percent(.x, decimals = 2)) 
    ) |&gt;

    tab_style(
      style = cell_fill(color = "#e6f0fa"),
      locations = cells_body(columns = pct, rows = pct &gt; .01)
    ) |&gt;
    tab_style(
      style = cell_fill(color = "#c5d6e9"),
      locations = cells_body(columns = pct, rows = pct &gt; .02)
    )

  return(tbl)
}




